from flask import Flask, redirect, request, session, url_for
import requests
import jwt

app = Flask(__name__)
app.secret_key = 'your_secret_key'
client_id = 'your_client_id'
redirect_uri = 'http://localhost:5000/callback'
authorization_endpoint = 'https://your-authorization-server.com/auth'
scope = 'openid'
response_type = 'id_token'

@app.route('/')
def home():
    return 'Welcome to the Admin Dashboard! <a href="/login">Login</a>'

@app.route('/login')
def login():
    auth_url = f"{authorization_endpoint}?client_id={client_id}&redirect_uri={redirect_uri}&scope={scope}&response_type={response_type}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if id_token:
        session['id_token'] = id_token
        return redirect(url_for('dashboard'))
    return 'Authentication failed', 400

@app.route('/dashboard')
def dashboard():
    if 'id_token' in session:
        id_token = session['id_token']
        decoded_token = jwt.decode(id_token, options={"verify_signature": False})
        return f"Hello, {decoded_token['sub']}! <a href='/logout'>Logout</a>"
    return redirect(url_for('home'))

@app.route('/logout')
def logout():
    session.pop('id_token', None)
    return redirect(url_for('home'))

if __name__ == '__main__':
    app.run(debug=True)